// ====================================================================
// Feed-URL-Liste (identisch zum Hauptworkflow)
// ====================================================================

const feeds = [
  { name: 'Heise Online IT',                  url: 'https://www.heise.de/rss/heise-atom.xml' },
  { name: 'Markt und Mittelstand',             url: 'https://www.marktundmittelstand.de/rss.xml' },
  { name: 'Handelsblatt Unternehmen',          url: 'https://www.handelsblatt.com/contentexport/feed/unternehmen' },
  { name: 'WirtschaftsWoche Unternehmen',      url: 'https://www.wiwo.de/contentexport/feed/rss/unternehmen' },
  { name: 't3n Digital Business',              url: 'https://t3n.de/rss.xml' },
  { name: 'Impulse Unternehmer-Magazin',       url: 'https://www.impulse.de/feed' },
  { name: 'Gründerszene',                      url: 'https://www.gruenderszene.de/feed' },
  { name: 'Deutsche Handwerks Zeitung',        url: 'https://www.deutsche-handwerks-zeitung.de/feed/' },
  { name: 'FAZ Wirtschaft',                    url: 'https://www.faz.net/rss/aktuell/wirtschaft/' },
  { name: 'Tagesschau Wirtschaft',             url: 'https://www.tagesschau.de/wirtschaft/index~rss2.xml' },
  { name: 'Spiegel Wirtschaft',                url: 'https://www.spiegel.de/wirtschaft/index.rss' },
  { name: 'Google News - KMU Mittelstand',     url: 'https://news.google.com/rss/search?q=KMU+Mittelstand+Deutschland&hl=de&gl=DE&ceid=DE:de' },
  { name: 'Google News - Digitalisierung',     url: 'https://news.google.com/rss/search?q=Digitalisierung+Mittelstand&hl=de&gl=DE&ceid=DE:de' },
  { name: 'Google News - Fachkräftemangel',    url: 'https://news.google.com/rss/search?q=Fachkr%C3%A4ftemangel+Mittelstand&hl=de&gl=DE&ceid=DE:de' },
  { name: 'Google News - Maschinenbau Elektro',url: 'https://news.google.com/rss/search?q=Maschinenbau+OR+Elektrotechnik+Mittelstand&hl=de&gl=DE&ceid=DE:de' },
  { name: 'Google News - Autohandel',          url: 'https://news.google.com/rss/search?q=Autohandel+OR+Kfz-Handel+Deutschland&hl=de&gl=DE&ceid=DE:de' }
];

return feeds.map(f => ({ json: f }));

// ====================================================================
// Health-Check-Auswertung
// Prüft jeden Feed auf: HTTP-Status, XML-Validität, Artikel-Anzahl
// ====================================================================

const items = $input.all();
const datum = new Date().toISOString();
const ergebnisse = [];
let ausgefallen = 0;
let gesund = 0;

for (const item of items) {
  const d = item.json;
  const result = { name: d.name || '?', url: d.url || '?' };

  // 1) HTTP-Fehler?
  if (d.error || (d.statusCode && d.statusCode >= 400)) {
    result.status = '❌ FEHLER';
    result.details = d.error?.message || `HTTP ${d.statusCode}`;
    result.gesund = false;
    ausgefallen++;
    ergebnisse.push(result);
    continue;
  }

  // 2) Body vorhanden?
  const body = typeof d.data === 'string' ? d.data
             : typeof d.response === 'string' ? d.response
             : typeof d.body === 'string' ? d.body : '';

  if (!body || body.trim().length === 0) {
    result.status = '❌ FEHLER';
    result.details = 'Leere Antwort';
    result.gesund = false;
    ausgefallen++;
    ergebnisse.push(result);
    continue;
  }

  // 3) XML/RSS?
  const isXml = body.includes('<rss') || body.includes('<feed') || body.includes('<?xml');
  if (!isXml) {
    result.status = '⚠️ WARNUNG';
    result.details = 'Kein RSS/XML-Format (evtl. HTML-Fehlerseite)';
    result.gesund = false;
    ausgefallen++;
    ergebnisse.push(result);
    continue;
  }

  // 4) Artikel vorhanden?
  const artikelCount = (body.match(/<item[\s>]/gi) || []).length
                     + (body.match(/<entry[\s>]/gi) || []).length;

  if (artikelCount === 0) {
    result.status = '⚠️ WARNUNG';
    result.details = 'XML valide, aber 0 Artikel gefunden';
    result.gesund = false;
    ausgefallen++;
  } else {
    result.status = '✅ OK';
    result.details = `${artikelCount} Artikel gefunden`;
    result.gesund = true;
    gesund++;
  }

  ergebnisse.push(result);
}

const bericht = {
  datum: datum,
  zusammenfassung: `${gesund} von ${ergebnisse.length} Feeds gesund, ${ausgefallen} mit Problemen`,
  gesund: gesund,
  ausgefallen: ausgefallen,
  gesamt: ergebnisse.length,
  alarm: ausgefallen > 0,
  feeds: ergebnisse
};

console.log(`🏥 Health Check: ${bericht.zusammenfassung}`);

return [{ json: bericht }];

// ====================================================================
// Alarm-E-Mail vorbereiten
// ====================================================================

const bericht = $input.first().json;
const ausgefallene = bericht.feeds.filter(f => !f.gesund);

const tabelle = ausgefallene.map(f =>
  `<tr><td style="padding:8px;border:1px solid #ddd">${f.name}</td>` +
  `<td style="padding:8px;border:1px solid #ddd">${f.status}</td>` +
  `<td style="padding:8px;border:1px solid #ddd">${f.details}</td>` +
  `<td style="padding:8px;border:1px solid #ddd;font-size:11px">${f.url}</td></tr>`
).join('');

const html = `
<h2>⚠️ RSS Feed Health Check – Ausfälle erkannt</h2>
<p><strong>Datum:</strong> ${new Date(bericht.datum).toLocaleDateString('de-DE', { weekday:'long', year:'numeric', month:'long', day:'numeric', hour:'2-digit', minute:'2-digit' })}</p>
<p><strong>Ergebnis:</strong> ${bericht.zusammenfassung}</p>
<hr>
<h3>Betroffene Feeds (${ausgefallene.length}):</h3>
<table style="border-collapse:collapse;width:100%">
  <tr style="background:#f44336;color:white">
    <th style="padding:8px;border:1px solid #ddd">Feed</th>
    <th style="padding:8px;border:1px solid #ddd">Status</th>
    <th style="padding:8px;border:1px solid #ddd">Details</th>
    <th style="padding:8px;border:1px solid #ddd">URL</th>
  </tr>
  ${tabelle}
</table>
<hr>
<p style="color:#666;font-size:12px">Automatischer Health Check – KMU News Workflow<br>
Bitte prüfe die betroffenen Feed-URLs und ersetze sie ggf. im Hauptworkflow.</p>
`;

return [{ json: {
  subject: `⚠️ RSS Feed Alarm: ${ausgefallene.length} von ${bericht.gesamt} Feeds ausgefallen`,
  html: html,
  bericht: bericht
}}];

const timestamp = new Date().toISOString().replace(/[:.+]/g, '-');
// Ergibt z.B.: log_2026-05-04T18-33-05-217-02-00.txt
const logText = `[${timestamp}] Dein Log-Eintrag hier`;

// Base64 kodieren
const logBase64 = Buffer.from(logText, 'utf-8').toString('base64');

return [{
  json: {
    logText: logBase64  // Base64-String
  }
}];
